const input = $input.first().json;
const action = input.action || 'list_projects';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.vikunja&select=cred_key,cred_value',
  headers: pgHeaders
});

if (!creds || creds.length === 0) {
  return [{ json: { error: 'Vikunja credentials not configured. Use add_credential to set them up.' } }];
}

const baseUrl = (creds.find(c => c.cred_key === 'vikunja_url')?.cred_value || '').replace(/\/$/, '');
const token = creds.find(c => c.cred_key === 'vikunja_token')?.cred_value;

if (!baseUrl || !token) {
  return [{ json: { error: 'Vikunja URL and API token are both required. Use add_credential to configure them.' } }];
}

const API = baseUrl + '/api/v1';
const apiHeaders = {
  'Authorization': 'Bearer ' + token,
  'Content-Type': 'application/json'
};

const priorityLabels = { 0: '', 1: 'Low', 2: 'Medium', 3: 'High', 4: 'Urgent' };

function formatTask(t) {
  let line = '- ';
  if (t.done) line += '[x] '; else line += '[ ] ';
  line += t.title;
  if (t.priority > 0) line += ' [' + (priorityLabels[t.priority] || 'P' + t.priority) + ']';
  if (t.due_date && t.due_date !== '0001-01-01T00:00:00Z') {
    line += ' (due: ' + t.due_date.substring(0, 10) + ')';
  }
  if (t.description) line += '\n  ' + t.description.substring(0, 100);
  return line;
}

// === list_projects ===
if (action === 'list_projects') {
  try {
    const projects = await helpers.httpRequest({
      method: 'GET',
      url: API + '/projects',
      headers: apiHeaders
    });

    if (!Array.isArray(projects) || projects.length === 0) {
      return [{ json: { result: 'No projects found.' } }];
    }

    let result = 'Projects (' + projects.length + '):\n\n';
    for (const p of projects) {
      result += '- **' + p.title + '** (ID: ' + p.id + ')';
      if (p.description) result += '\n  ' + p.description.substring(0, 100);
      if (p.is_archived) result += ' [archived]';
      result += '\n';
    }

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list projects: ' + err.message } }];
  }

// === list_tasks ===
} else if (action === 'list_tasks') {
  const projectId = input.project_id;
  if (!projectId) return [{ json: { error: 'Parameter "project_id" is required. Use vikunja_list_projects to find project IDs.' } }];

  try {
    let url = API + '/projects/' + projectId + '/tasks';
    const params = [];
    if (input.page && input.page !== '') params.push('page=' + input.page);
    if (input.per_page && input.per_page !== '') params.push('per_page=' + input.per_page);
    if (input.sort_by && input.sort_by !== '') params.push('sort_by=' + encodeURIComponent(input.sort_by));
    if (input.order_by && input.order_by !== '') params.push('order_by=' + encodeURIComponent(input.order_by));
    if (params.length > 0) url += '?' + params.join('&');

    const tasks = await helpers.httpRequest({ method: 'GET', url, headers: apiHeaders });

    if (!Array.isArray(tasks) || tasks.length === 0) {
      return [{ json: { result: 'No tasks found in this project.' } }];
    }

    let result = 'Tasks (' + tasks.length + '):\n\n';
    for (const t of tasks.slice(0, 25)) {
      result += formatTask(t) + '\n  ID: ' + t.id + '\n\n';
    }
    if (tasks.length > 25) result += '(' + (tasks.length - 25) + ' more tasks not shown)';

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list tasks: ' + err.message } }];
  }

// === get_task ===
} else if (action === 'get_task') {
  const taskId = input.task_id;
  if (!taskId) return [{ json: { error: 'Parameter "task_id" is required.' } }];

  try {
    const task = await helpers.httpRequest({
      method: 'GET',
      url: API + '/tasks/' + taskId,
      headers: apiHeaders
    });

    let result = '**' + task.title + '**\n';
    result += 'ID: ' + task.id + '\n';
    result += 'Status: ' + (task.done ? 'Done' : 'Open') + '\n';
    if (task.priority > 0) result += 'Priority: ' + (priorityLabels[task.priority] || task.priority) + '\n';
    if (task.due_date && task.due_date !== '0001-01-01T00:00:00Z') {
      result += 'Due: ' + task.due_date.substring(0, 10) + '\n';
    }
    if (task.description) result += '\nDescription:\n' + task.description + '\n';
    if (task.labels && task.labels.length > 0) {
      result += 'Labels: ' + task.labels.map(l => l.title).join(', ') + '\n';
    }
    result += 'Created: ' + (task.created || '?') + '\n';
    result += 'Updated: ' + (task.updated || '?') + '\n';
    if (task.project_id) result += 'Project ID: ' + task.project_id + '\n';

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get task: ' + err.message } }];
  }

// === create_task ===
} else if (action === 'create_task') {
  const projectId = input.project_id;
  const title = input.title;
  if (!projectId) return [{ json: { error: 'Parameter "project_id" is required.' } }];
  if (!title) return [{ json: { error: 'Parameter "title" is required.' } }];

  try {
    const body = { title };
    if (input.description && input.description !== '') body.description = input.description;
    if (input.due_date && input.due_date !== '') body.due_date = input.due_date;
    if (input.priority && input.priority !== '') body.priority = parseInt(input.priority) || 0;

    const task = await helpers.httpRequest({
      method: 'PUT',
      url: API + '/projects/' + projectId + '/tasks',
      headers: apiHeaders,
      body: JSON.stringify(body)
    });

    const parsed = typeof task === 'string' ? JSON.parse(task) : task;
    let result = 'Task created: **' + parsed.title + '**';
    if (parsed.due_date && parsed.due_date !== '0001-01-01T00:00:00Z') {
      result += ' (due: ' + parsed.due_date.substring(0, 10) + ')';
    }
    result += '\nID: ' + parsed.id;

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create task: ' + err.message } }];
  }

// === update_task ===
} else if (action === 'update_task') {
  const taskId = input.task_id;
  if (!taskId) return [{ json: { error: 'Parameter "task_id" is required.' } }];

  try {
    const body = {};
    if (input.title && input.title !== '') body.title = input.title;
    if (input.description && input.description !== '') body.description = input.description;
    if (input.due_date && input.due_date !== '') body.due_date = input.due_date;
    if (input.done && input.done !== '') body.done = input.done === 'true';
    if (input.priority && input.priority !== '') body.priority = parseInt(input.priority) || 0;

    if (Object.keys(body).length === 0) {
      return [{ json: { error: 'No fields to update. Provide at least one of: title, description, due_date, done, priority.' } }];
    }

    const task = await helpers.httpRequest({
      method: 'POST',
      url: API + '/tasks/' + taskId,
      headers: apiHeaders,
      body: JSON.stringify(body)
    });

    const parsed = typeof task === 'string' ? JSON.parse(task) : task;
    let result = 'Task ' + taskId + ' updated: **' + (parsed.title || '') + '**';
    if (parsed.done) result += ' [Done]';
    result += '\nID: ' + parsed.id;

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to update task: ' + err.message } }];
  }

// === delete_task ===
} else if (action === 'delete_task') {
  const taskId = input.task_id;
  if (!taskId) return [{ json: { error: 'Parameter "task_id" is required.' } }];

  try {
    await helpers.httpRequest({
      method: 'DELETE',
      url: API + '/tasks/' + taskId,
      headers: apiHeaders
    });
    return [{ json: { result: 'Task ' + taskId + ' deleted.' } }];
  } catch (err) {
    return [{ json: { error: 'Failed to delete task: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use list_projects, list_tasks, get_task, create_task, update_task, or delete_task.' } }];
}
